vfs_linux_passthrough_abs(char *path)
{
  if(path == 0 || path[0] != '/')
    return 0;
  if((strncmp(path, "/dev", 4) == 0 && (path[4] == 0 || path[4] == '/')) ||
     (strncmp(path, "/proc", 5) == 0 && (path[5] == 0 || path[5] == '/')) ||
     (strncmp(path, "/tmp", 4) == 0 && (path[4] == 0 || path[4] == '/')) ||
     (strncmp(path, "/bin", 4) == 0 && (path[4] == 0 || path[4] == '/')))
    return 1;
  return 0;
}

