// Resolve a process-relative path through VFS and open it as a regular file.
// On success, vp records the resolved VFS location and *fp is the opened file.
static int
exec_open_vfs(char *path, struct vfs_path *vp, struct file **fp)
{
  struct proc *p = myproc();
  struct vfs_node node;

  if(vfs_resolve_proc_path(p, path, vp) < 0)
    return -1;
  if(vp->ops == 0 || vp->ops->inode == 0 || vp->ops->inode->lookup == 0 ||
     vp->ops->file == 0 || vp->ops->file->open == 0)
    return -1;
  if(vp->ops->inode->lookup(vp->mount, vp->inner, &node) < 0 ||
     node.type != T_FILE)
    return -1;
  return vp->ops->file->open(vp->mount, vp->inner, 0, fp);
}

// Open the dynamic linker named by PT_INTERP.  Linux binaries from ext4 may
// name /lib/..., which we redirect into the mounted glibc or musl trees.
static int
exec_open_interp(char *path, int from_ext4, struct vfs_path *vp, struct file **fp)
{
  char full[MAXPATH];
  struct proc *p = myproc();
  int rooted_ext4 = p->vfs_root.mount && p->vfs_root.mount->type == VFS_EXT4;

  if(from_ext4 && path[0] == '/'){
    if(strncmp(path, "/lib/", 5) == 0){
      snprintf(full, sizeof(full), rooted_ext4 ? "/glibc%s" : "/ext4/glibc%s", path);
      if(exec_open_vfs(full, vp, fp) == 0)
        return 0;
      snprintf(full, sizeof(full), rooted_ext4 ? "/musl%s" : "/ext4/musl%s", path);
      if(exec_open_vfs(full, vp, fp) == 0)
        return 0;
      if(strncmp(path, "/lib/ld-musl-", 13) == 0){
        snprintf(full, sizeof(full), rooted_ext4 ? "/musl/lib/libc.so" : "/ext4/musl/lib/libc.so");
        if(exec_open_vfs(full, vp, fp) == 0)
          return 0;
      }
    }
    snprintf(full, sizeof(full), rooted_ext4 ? "%s" : "/ext4%s", path);
    return exec_open_vfs(full, vp, fp);
  }
  return exec_open_vfs(path, vp, fp);
}

// Non-ELF files are treated as shell scripts handled by busybox sh.
// This keeps script handling in user space instead of teaching the kernel
// about every possible shebang interpreter.
static int
exec_nonelf(char *script, char **argv)
{
  struct script_exec *se;
  int i;
  int n = 0;
  int ret;
  struct proc *p = myproc();

  se = (struct script_exec *)kalloc();
  if(se == 0)
    return -1;
  memset(se, 0, sizeof(*se));

  if(p->vfs_root.mount && p->vfs_root.mount->type == VFS_EXT4)
    safestrcpy(se->interp, "/musl/busybox", sizeof(se->interp));
  else
    safestrcpy(se->interp, "/ext4/musl/busybox", sizeof(se->interp));
  safestrcpy(se->iarg, "sh", sizeof(se->iarg));

  se->nargv[n++] = se->interp;
  if(se->iarg[0])
    se->nargv[n++] = se->iarg;
  se->nargv[n++] = script;
  for(i = 1; argv[i] && n < MAXARG - 1; i++)
    se->nargv[n++] = argv[i];
  se->nargv[n] = 0;

  ret = kexec(se->interp, se->nargv);
  kfree(se);
  return ret;
}

// Map ELF segment permissions to the small subset of PTE bits we use here.
int flags2perm(int flags)
{
    int perm = 0;
    if(flags & 0x1)
      perm = PTE_X;
    if(flags & 0x2)
      perm |= PTE_W;
    return perm;
}

// Replace the current process image with path.  Most work happens in a fresh
// pagetable first; the old image is discarded only after every load step works.
int
kexec(char *path, char **argv)
{
  struct exec_state *st;
  char *s, *last;
  int i, off;
  int is_ext4 = 0;
  int has_interp = 0;
  uint64 argc, sz = 0, sp, stackbase, phdr_addr = 0;
  uint64 app_brk, at_base = 0, entry;
  int stack_pages;
  struct file *ef = 0;
  struct file *interp_f = 0;
  pagetable_t pagetable = 0, oldpagetable;
  struct proc *p = myproc();
  int ret;
  int reset_group;

  st = (struct exec_state *)kalloc();
  if(st == 0)
    return -1;
  memset(st, 0, sizeof(*st));

  if(exec_open_vfs(path, &st->vp, &ef) < 0){
    kfree(st);
    return -1;
  }
  safestrcpy(st->epath, st->vp.type == VFS_EXT4 ? st->vp.inner : st->vp.abs_path,
             sizeof(st->epath));
  is_ext4 = st->vp.type == VFS_EXT4;
  if(is_ext4)
    exec_linux_visible_path(&st->vp, st->linux_epath, sizeof(st->linux_epath));
  else
    st->linux_epath[0] = 0;

  // acquire the ELF header.
  if(vfs_file_read_kernel(ef, (char *)&st->elf, sizeof(st->elf), 0) != sizeof(st->elf))
    goto bad;

  // Is this really an ELF file?
  if(st->elf.magic != ELF_MAGIC){
    fileclose(ef);
    ef = 0;
    ret = exec_nonelf(path, argv);
    kfree(st);
    return ret;
  }

  if((pagetable = proc_pagetable(p)) == 0)
    goto bad;

  // Load program into memory and find an optional Linux interpreter.
  for(i=0, off=st->elf.phoff; i<st->elf.phnum; i++, off+=sizeof(st->ph)){
    if(vfs_file_read_kernel(ef, (char *)&st->ph, sizeof(st->ph), off) != sizeof(st->ph))
      goto bad;
    if(st->ph.type == ELF_PROG_INTERP && is_ext4){
      if(st->ph.filesz == 0 || st->ph.filesz >= sizeof(st->interp))
        goto bad;
      if(vfs_file_read_kernel(ef, st->interp, st->ph.filesz, st->ph.off) != st->ph.filesz)
        goto bad;
      st->interp[st->ph.filesz - 1] = 0;
      has_interp = 1;
    }
  }
  if(load_elf_load_segments(pagetable, ef, &st->elf, &st->ph, 0, &sz,
                            &phdr_addr) < 0)
    goto bad;
  fileclose(ef);
  ef = 0;

  entry = st->elf.entry;
  app_brk = PGROUNDUP(sz);

  if(has_interp){
    uint64 base;

    if(exec_open_interp(st->interp, is_ext4, &st->vp, &interp_f) < 0)
      goto bad;
    safestrcpy(st->interp_epath, st->vp.type == VFS_EXT4 ? st->vp.inner : st->vp.abs_path,

    safestrcpy(st->interp_epath, st->vp.type == VFS_EXT4 ? st->vp.inner : st->vp.abs_path,
               sizeof(st->interp_epath));
    if(vfs_file_read_kernel(interp_f, (char *)&st->ielf, sizeof(st->ielf), 0) != sizeof(st->ielf))
      goto bad;
    if(st->ielf.magic != ELF_MAGIC)
      goto bad;

    base = PGROUNDUP(sz) + 16 * PGSIZE;
    at_base = base;
    if(load_elf_load_segments(pagetable, interp_f, &st->ielf, &st->ph, base,
                              &sz, 0) < 0)
      goto bad;
    fileclose(interp_f);
    interp_f = 0;
    entry = base + st->ielf.entry;
  }

  p = myproc();
  uint64 oldsz = p->mm ? p->mm->sz : 0;
  uint64 linux_brk = 0;
  uint64 linux_brk_limit = 0;

  // Allocate some pages at the next page boundary.
  // Make the first inaccessible as a stack guard.
  // Use the rest as the user stack.
  sz = PGROUNDUP(sz);
  if(is_ext4)
    linux_brk = app_brk;
  if(is_ext4)
    sz += has_interp ? 16 * PGSIZE : 4096 * PGSIZE;
  if(is_ext4)
    linux_brk_limit = has_interp ? at_base : sz;
  stack_pages = is_ext4 ? 16 : USERSTACK;
  uint64 sz1;
  if((sz1 = uvmalloc(pagetable, sz, sz + (stack_pages+1)*PGSIZE, PTE_W)) == 0)
    goto bad;
  sz = sz1;
  uvmclear(pagetable, sz-(stack_pages+1)*PGSIZE);
  sp = sz;
  stackbase = sp - stack_pages*PGSIZE;

  // Copy argument strings into new stack, remember their
  // addresses in ustack[].
  for(argc = 0; argv[argc]; argc++) {
    if(argc >= MAXARG)
      goto bad;
    sp -= strlen(argv[argc]) + 1;
    sp -= sp % 16; // riscv sp must be 16-byte aligned
    if(sp < stackbase)
      goto bad;
    if(copyout(pagetable, sp, argv[argc], strlen(argv[argc]) + 1) < 0)
      goto bad;
    st->ustack[argc] = sp;
  }
  st->ustack[argc] = 0;

  {
    uint64 rand_addr, execfn_addr, argv_addr, envp_addr, auxv_addr;
    uint64 random[2] = {0, 0};
    int auxbytes = sizeof(st->auxv);
    int total;

    execfn_addr = 0;
    if(is_ext4){
      sp -= strlen(st->linux_epath) + 1;
      sp -= sp % 16;
      execfn_addr = sp;
      if(sp < stackbase ||
         copyout(pagetable, execfn_addr, st->linux_epath,
                 strlen(st->linux_epath) + 1) < 0)
        goto bad;
    }

    sp -= sizeof(random);
    sp -= sp % 16;
    rand_addr = sp;
    build_auxv(st->auxv, phdr_addr, &st->elf, at_base, rand_addr, execfn_addr);
    if(sp < stackbase || copyout(pagetable, rand_addr, (char *)random, sizeof(random)) < 0)
      goto bad;

    total = sizeof(uint64) + (argc + 1) * sizeof(uint64) +
            sizeof(uint64) + auxbytes;
    sp -= total;
    sp -= sp % 16;
    if(sp < stackbase)
      goto bad;

    argv_addr = sp + sizeof(uint64);
    envp_addr = argv_addr + (argc + 1) * sizeof(uint64);
    auxv_addr = envp_addr + sizeof(uint64);

    if(copyout(pagetable, sp, (char *)&argc, sizeof(argc)) < 0)
      goto bad;
    if(copyout(pagetable, argv_addr, (char *)st->ustack, (argc+1)*sizeof(uint64)) < 0)
      goto bad;
    uint64 zero = 0;
    if(copyout(pagetable, envp_addr, (char *)&zero, sizeof(zero)) < 0)
      goto bad;
    if(copyout(pagetable, auxv_addr, (char *)st->auxv, auxbytes) < 0)
      goto bad;

    // xv6 user programs enter main directly; Linux ABI programs read from sp.
    p->trapframe->a1 = argv_addr;
    p->trapframe->a2 = envp_addr;
    p->trapframe->ra = 0;
  }

  // Save program name for debugging.
  for(last=s=path; *s; s++)
    if(*s == '/')
      last = s+1;
  safestrcpy(p->name, last, sizeof(p->name));

  // Commit to the user image.
  reset_group = p->is_linux;
  if(p->is_linux){
    for(struct proc *q = proc; q < &proc[NPROC]; q++){
      if(q == p || q->state == UNUSED || linux_tgid(q) != linux_tgid(p))
        continue;
      acquire(&q->lock);
      q->killed = 1;
      if(q->state == SLEEPING)
        q->state = RUNNABLE;
      release(&q->lock);
    }
    p->linux_is_thread = 0;
  }
  oldpagetable = p->pagetable;
  proc_munmapall(p);
  p->pagetable = pagetable;
  p->is_linux = is_ext4;
  p->linux_signal_pending = 0;
  p->linux_pending_signal = 0;
  p->linux_pending_sender = 0;
  p->linux_in_signal = 0;
  p->linux_share_vm = 0;
  p->linux_share_files = 0;
  p->linux_share_fs = 0;
  p->linux_is_thread = 0;
  if(reset_group || p->linux_group == 0)
    linux_reset_thread_group(p);
  p->linux_rt_signal_handler = 0;
  p->linux_sigmask = 0;
  p->clear_child_tid = 0;
  p->pincpu = is_ext4 ? &cpus[0] : 0;
  if(is_ext4){
    vfs_set_proc_root(p, "/ext4");
    safestrcpy(p->linux_exe_path, st->linux_epath, sizeof(p->linux_exe_path));
  } else {
    vfs_set_proc_root(p, "/");
    p->linux_exe_path[0] = 0;
  }
  if(p->mm){
    p->mm->pagetable = p->pagetable;
    p->mm->sz = sz;
    p->mm->linux_brk = linux_brk;
    p->mm->linux_brk_limit = linux_brk_limit;
    p->mm->mmap_base = MMAP_TOP;
    memset(p->mm->vmas, 0, sizeof(p->mm->vmas));
  }
  p->trapframe->epc = entry;  // initial program counter
  p->trapframe->sp = sp; // initial stack pointer
  proc_freepagetable(oldpagetable, oldsz, p->trapframe_va);
  for(i = 0; i < NOFILE; i++){
    if(p->ofile[i] && (p->ofd_flags[i] & 1)){
      struct file *f = p->ofile[i];
      p->ofile[i] = 0;
      p->ofd_flags[i] = 0;
      fileclose(f);
    }
  }

  // xv6 programs enter main(argc, argv). Linux ABI programs enter _start;
  // on RISC-V a0 is rtld_fini, so keep it null and let _start read argc
  // from the initial stack.
  ret = is_ext4 ? 0 : argc;
  kfree(st);
  return ret;

 bad:
  if(pagetable)
    proc_freepagetable(pagetable, sz, p->trapframe_va);
  if(ef)
    fileclose(ef);
  if(interp_f)
    fileclose(interp_f);
  kfree(st);
  return -1;
}

// Load every PT_LOAD segment from an ELF file.  base is zero for the main
// program and nonzero when placing a dynamic linker above the program image.
static int
load_elf_load_segments(pagetable_t pagetable, struct file *f,
                       struct elfhdr *elf, struct proghdr *ph, uint64 base,
                       uint64 *sz, uint64 *phdr_addr)
{
  int i, off;

  for(i = 0, off = elf->phoff; i < elf->phnum; i++, off += sizeof(*ph)){
    if(vfs_file_read_kernel(f, (char *)ph, sizeof(*ph), off) != sizeof(*ph))

    pa += va & (SUPERPGSIZE - 1);
  else
    pa += va & (PGSIZE - 1);

  return pa;
}

void
vmprint(pagetable_t pagetable) {
  printf("page table %p\n", pagetable);
  int start_level = 2;

  for(int i = 0; i < 512; i++) {
    pte_t pte = pagetable[i];
    if((pte & PTE_V) == 0)
      continue;
    uint64 va = ((uint64)i << PXSHIFT(start_level));
    for(int d = 0; d < 1; d++)
      printf(" ..");
    printf("%p: pte %p pa %p\n", (void*)va, (void*)pte, (void*)PTE2PA(pte));
    if((pte & (PTE_R|PTE_W|PTE_X)) == 0) {
      pagetable_t child = (pagetable_t)PTE2PA(pte);
      for(int j = 0; j < 512; j++) {
        pte_t pte1 = child[j];
        if((pte1 & PTE_V) == 0)
          continue;
        uint64 va1 = va | ((uint64)j << PXSHIFT(start_level - 1));
        for(int d = 0; d < 2; d++)
          printf(" ..");
        printf("%p: pte %p pa %p\n", (void*)va1, (void*)pte1, (void*)PTE2PA(pte1));
        if((pte1 & (PTE_R|PTE_W|PTE_X)) == 0) {
          pagetable_t child2 = (pagetable_t)PTE2PA(pte1);
          for(int k = 0; k < 512; k++) {
            pte_t pte2 = child2[k];
            if((pte2 & PTE_V) == 0)
              continue;
            uint64 va2 = va1 | ((uint64)k << PXSHIFT(start_level - 2));
            for(int d = 0; d < 3; d++)
              printf(" ..");
            printf("%p: pte %p pa %p\n", (void*)va2, (void*)pte2, (void*)PTE2PA(pte2));
          }
        }
      }
    }
  }
}

// Create PTEs for virtual addresses starting at va that refer to
// physical addresses starting at pa.
// va and size MUST be page-aligned.
// Returns 0 on success, -1 if walk() couldn't
// allocate a needed page-table page.
int
mappages(pagetable_t pagetable, uint64 va, uint64 size, uint64 pa, int perm)
{
  uint64 a, last;
  pte_t *pte;

  if((va % PGSIZE) != 0)
    panic("mappages: va not aligned");

  if((size % PGSIZE) != 0)
    panic("mappages: size not aligned");

  if(size == 0)
    panic("mappages: size");

  a = va;
  last = va + size - PGSIZE;
  for(;;){
    if((pte = walk(pagetable, a, 1)) == 0)
      return -1;
    if(*pte & PTE_V)
      panic("mappages: remap");
    *pte = PA2PTE(pa) | perm | PTE_V;
    if(a == last)
      break;
    a += PGSIZE;
    pa += PGSIZE;
  }
  return 0;
}

// create an empty user page table.
// returns 0 if out of memory.
pagetable_t
uvmcreate()
{
  pagetable_t pagetable;
  pagetable = (pagetable_t) kalloc();
  if(pagetable == 0)
    return 0;
  memset(pagetable, 0, PGSIZE);
  return pagetable;
}

// Remove npages of mappings starting from va. va must be
// page-aligned. It's OK if the mappings don't exist.
// Optionally free the physical memory.
void
uvmunmap(pagetable_t pagetable, uint64 va, uint64 npages, int do_free)
{
  uint64 a;
  pte_t *pte;
  int sz = PGSIZE;

  if((va % PGSIZE) != 0)
    panic("uvmunmap: not aligned");

  for(a = va; a < va + npages*PGSIZE; a += sz){
    int level = 0;
    pte = walk_with_level(pagetable, a, 0, &level);

    if(pte == 0)
      continue;
    if((*pte & PTE_V) == 0)
      continue;

    if(level == 1 && PTE_LEAF(*pte)) {
      uint64 remaining = va + npages*PGSIZE - a;
      if((a % SUPERPGSIZE) == 0 && remaining >= SUPERPGSIZE) {
        sz = SUPERPGSIZE;
        if(do_free)
          superfree((void*)PTE2PA(*pte));
        *pte = 0;
        continue;
      }
      // Demote superpage to 4K pages for partial unmap.
      uint64 super_pa = PTE2PA(*pte);
      pagetable_t newpt = uvmcreate();
      if(newpt == 0)
        panic("uvmunmap: demote alloc");
      memset(newpt, 0, PGSIZE);
      uint flags = PTE_FLAGS(*pte);
      for(int i = 0; i < 512; i++) {
        char *mem = kalloc();
        if(mem == 0)
          panic("uvmunmap: demote page");
        memmove(mem, (void*)(super_pa + i * PGSIZE), PGSIZE);
        newpt[i] = PA2PTE(mem) | (flags | PTE_V);
      }
      superfree((void*)super_pa);
      *pte = PA2PTE(newpt) | PTE_V;
      pte = walk(pagetable, a, 0);
      if(pte == 0)
        panic("uvmunmap: demote walk");
      sz = PGSIZE;
    }

    if(PTE_FLAGS(*pte) == PTE_V)
      panic("uvmunmap: not a leaf");
    if(do_free){
      uint64 pa = PTE2PA(*pte);
      kfree((void*)pa);
    }
    *pte = 0;
    sz = PGSIZE;
  }
}


// Allocate PTEs and physical memory to grow process from oldsz to
// newsz, which need not be page aligned.  Returns new size or 0 on error.
uint64
uvmalloc(pagetable_t pagetable, uint64 oldsz, uint64 newsz, int xperm)
{
  char *mem;
  uint64 a;
  int sz;

  if(newsz < oldsz)
    return oldsz;

  oldsz = PGROUNDUP(oldsz);
  for(a = oldsz; a < newsz; a += sz){
    sz = PGSIZE;
    if((a % SUPERPGSIZE) == 0 && newsz - a >= SUPERPGSIZE) {
      mem = superalloc();
      if(mem != 0){
        memset(mem, 0, SUPERPGSIZE);
        pte_t *pte = walk_to_level(pagetable, a, 1, 1);
        if(pte == 0) {
          superfree(mem);
          uvmdealloc(pagetable, a, oldsz);
          return 0;
        }
        if((*pte & PTE_V) == 0) {
          *pte = PA2PTE(mem) | PTE_R|PTE_U|xperm | PTE_V;
          sz = SUPERPGSIZE;
          continue;
        }
        // Existing page-table page prevents superpage mapping; fall back to 4K.
        superfree(mem);
      }
    }
    // Fall back to 4K pages when superpage pool is exhausted.
    mem = kalloc();
    if(mem == 0){
      uvmdealloc(pagetable, a, oldsz);
      return 0;
    }

    }
    memset(mem, 0, sz);
    if(mappages(pagetable, a, sz, (uint64)mem, PTE_R|PTE_U|xperm) != 0){
      kfree(mem);
      uvmdealloc(pagetable, a, oldsz);
      return 0;
    }
  }
  return newsz;
}

// Deallocate user pages to bring the process size from oldsz to
// newsz.  oldsz and newsz need not be page-aligned, nor does newsz
// need to be less than oldsz.  oldsz can be larger than the actual
// process size.  Returns the new process size.
uint64
uvmdealloc(pagetable_t pagetable, uint64 oldsz, uint64 newsz)
{
  if(newsz >= oldsz)
    return oldsz;

  if(PGROUNDUP(newsz) < PGROUNDUP(oldsz)){
    int npages = (PGROUNDUP(oldsz) - PGROUNDUP(newsz)) / PGSIZE;
    uvmunmap(pagetable, PGROUNDUP(newsz), npages, 1);
  }

  return newsz;
}

// Recursively free page-table pages.
// All leaf mappings must already have been removed.
void
freewalk(pagetable_t pagetable)
{
  // there are 2^9 = 512 PTEs in a page table.
  for(int i = 0; i < 512; i++){
    pte_t pte = pagetable[i];
    if((pte & PTE_V) && (pte & (PTE_R|PTE_W|PTE_X)) == 0){
      // this PTE points to a lower-level page table.
      uint64 child = PTE2PA(pte);
      freewalk((pagetable_t)child);
      pagetable[i] = 0;
    } else if(pte & PTE_V){
      // backtrace();
      panic("freewalk: leaf");
    }
  }
  kfree((void*)pagetable);
}

static void
uvmunmap_all_walk(pagetable_t pagetable, int level)
{
  for(int i = 0; i < 512; i++){
    pte_t pte = pagetable[i];

    if((pte & PTE_V) == 0)
      continue;
    if((pte & (PTE_R|PTE_W|PTE_X)) == 0){
      uvmunmap_all_walk((pagetable_t)PTE2PA(pte), level - 1);
      continue;
    }
    if(level == 1)
      superfree((void*)PTE2PA(pte));
    else
      kfree((void*)PTE2PA(pte));
    pagetable[i] = 0;
  }
}

void
uvmunmap_all(pagetable_t pagetable)
{
  uvmunmap_all_walk(pagetable, 2);
}

// Free user memory pages,
// then free page-table pages.
void
uvmfree(pagetable_t pagetable, uint64 sz)
{
  if(sz > 0)
    uvmunmap(pagetable, 0, PGROUNDUP(sz)/PGSIZE, 1);
  freewalk(pagetable);
}

// Given a parent process's page table, copy
// its memory into a child's page table.
// Copies both the page table and the
// physical memory.
// returns 0 on success, -1 on failure.
// frees any allocated pages on failure.
int
uvmcopy(pagetable_t old, pagetable_t new, uint64 sz)
{
  pte_t *pte;
  uint64 pa, i;
  uint flags;
  int szinc = PGSIZE;

  for(i = 0; i < sz; i += szinc){
    int level = 0;
    if((pte = walk_with_level(old, i, 0, &level)) == 0)
      continue;

    if((*pte & PTE_V) == 0)
      continue;
    //if superpage
    if(level == 1 && PTE_LEAF(*pte)) {
      if((i % SUPERPGSIZE) != 0)
        panic("uvmcopy: unaligned superpage");
      pa = PTE2PA(*pte);
      flags = PTE_FLAGS(*pte);

      //convert writable to cow and set the flag
      if(flags & PTE_W){
        flags = (flags & ~PTE_W) | PTE_COW;
        *pte = PA2PTE(pa) | flags;
      }
      pte_t *npte = walk_to_level(new, i, 1, 1);
      if(npte == 0 || (*npte & PTE_V)) {
        goto err;
      }
      *npte = PA2PTE(pa) | flags | PTE_V;
      superref_inc(pa);
      szinc = SUPERPGSIZE;
      continue;
    }

    //if normal page, do the same thing
    szinc = PGSIZE;
    pa = PTE2PA(*pte);
    flags = PTE_FLAGS(*pte);
    if(flags & PTE_W){
      flags = (flags & ~PTE_W) | PTE_COW;
      *pte = PA2PTE(pa) | flags;
    }
    pte_t *npte = walk(new, i, 0);
    if(npte && (*npte & PTE_V)){
      szinc = PGSIZE;
      continue;
    }
    if(mappages(new, i, PGSIZE, pa, flags) != 0)
      goto err;
    kref_inc(pa);
  }
  sfence_vma();
  return 0;

 err:
  uvmunmap(new, 0, i / PGSIZE, 1);
  return -1;
}

// Copy user mappings into a child page table while keeping the underlying
// physical pages shared and writable. Used for Linux CLONE_VM threads.
int
uvmshare(pagetable_t old, pagetable_t new, uint64 sz)
{
  pte_t *pte;
  uint64 pa, i;
  uint flags;
  int szinc = PGSIZE;

  for(i = 0; i < sz; i += szinc){
    int level = 0;
    if((pte = walk_with_level(old, i, 0, &level)) == 0)
      continue;

    if((*pte & PTE_V) == 0)
      continue;
    //if superpage
    if(level == 1 && PTE_LEAF(*pte)){
      if((i % SUPERPGSIZE) != 0)
        panic("uvmshare: unaligned superpage");
      pa = PTE2PA(*pte);
      flags = PTE_FLAGS(*pte);

      //estimate the cow flag cause we should share the page
      if(flags & PTE_COW){
        flags = (flags | PTE_W) & ~PTE_COW;
        if(superref_get(pa) == 1){
          *pte = PA2PTE(pa) | flags;
        } else {
          char *mem = superalloc();
          if(mem == 0)
            goto err;
          memmove(mem, (void *)pa, SUPERPGSIZE);
          *pte = PA2PTE(mem) | flags;
          superfree((void *)pa);
          pa = (uint64)mem;
        }
      }
      pte_t *npte = walk_to_level(new, i, 1, 1);
      if(npte == 0 || (*npte & PTE_V))
        goto err;
      *npte = PA2PTE(pa) | flags | PTE_V;
      superref_inc(pa);
      szinc = SUPERPGSIZE;
      continue;
    }

    }

    //if normal page, do the same thing
    szinc = PGSIZE;
    pa = PTE2PA(*pte);
    flags = PTE_FLAGS(*pte);
    if(flags & PTE_COW){
      flags = (flags | PTE_W) & ~PTE_COW;
      if(kref_get(pa) == 1){
        *pte = PA2PTE(pa) | flags;
      } else {
        char *mem = kalloc();
        if(mem == 0)
          goto err;
        memmove(mem, (void *)pa, PGSIZE);
        *pte = PA2PTE(mem) | flags;
        kfree((void *)pa);
        pa = (uint64)mem;
      }
    }
    if(mappages(new, i, PGSIZE, pa, flags) != 0)
      goto err;
    kref_inc(pa);
  }
  sfence_vma();
  return 0;

 err:
  uvmunmap(new, 0, i / PGSIZE, 1);
  return -1;
}

// mark a PTE invalid for user access.
// used by exec for the user stack guard page.
void
uvmclear(pagetable_t pagetable, uint64 va)
{
  pte_t *pte;

  pte = walk(pagetable, va, 0);
  if(pte == 0)
    panic("uvmclear");
  *pte &= ~PTE_U;
}

// Copy from kernel to user.
// Copy len bytes from src to virtual address dstva in a given page table.
// Return 0 on success, -1 on error.
int
copyout(pagetable_t pagetable, uint64 dstva, char *src, uint64 len)
{
  uint64 n, va0, pa0;
  pte_t *pte;
  if(dstva >= MAXVA || len > MAXVA - dstva)
    return -1;

  while(len > 0){
    va0 = PGROUNDDOWN(dstva);
    if (va0 >= MAXVA)
      return -1;

    pa0 = walkaddr(pagetable, va0);
    if(pa0 == 0) {
      if((pa0 = vmfault(pagetable, va0, 0)) == 0) {
        return -1;
      }
    }

    pte = walk(pagetable, va0, 0);
    if((*pte & PTE_COW) != 0){
      if((pa0 = vmfault(pagetable, va0, 0)) == 0)
        return -1;
      pte = walk(pagetable, va0, 0);
    }
    // forbid copyout over read-only user text pages.
    if((*pte & PTE_W) == 0)
      return -1;

    n = PGSIZE - (dstva - va0);
    if(n > len)
      n = len;
    memmove((void *)(pa0 + (dstva - va0)), src, n);

    len -= n;
    src += n;
    dstva = va0 + PGSIZE;
  }
  return 0;
}

// Copy from user to kernel.
// Copy len bytes to dst from virtual address srcva in a given page table.
// Return 0 on success, -1 on error.
int
copyin(pagetable_t pagetable, char *dst, uint64 srcva, uint64 len)
{
  uint64 n, va0, pa0;
  if(srcva >= MAXVA || len > MAXVA - srcva)
    return -1;

  while(len > 0){
    va0 = PGROUNDDOWN(srcva);
    pa0 = walkaddr(pagetable, va0);
    if(pa0 == 0) {
      if((pa0 = vmfault(pagetable, va0, 1)) == 0) {
        return -1;
      }
    }
    n = PGSIZE - (srcva - va0);
    if(n > len)
      n = len;
    memmove(dst, (void *)(pa0 + (srcva - va0)), n);

    len -= n;
    dst += n;
    srcva = va0 + PGSIZE;
  }
  return 0;
}

// Copy a null-terminated string from user to kernel.
// Copy bytes to dst from virtual address srcva in a given page table,
// until a '\0', or max.
// Return 0 on success, -1 on error.
int
copyinstr(pagetable_t pagetable, char *dst, uint64 srcva, uint64 max)
{
  uint64 n, va0, pa0;
  int got_null = 0;
  if(srcva >= MAXVA)
    return -1;

  while(got_null == 0 && max > 0){
    va0 = PGROUNDDOWN(srcva);
    if(va0 >= MAXVA)
      return -1;
    pa0 = walkaddr(pagetable, va0);
    if(pa0 == 0){
      if((pa0 = vmfault(pagetable, va0, 1)) == 0)
        return -1;
    }
    n = PGSIZE - (srcva - va0);
    if(n > max)
      n = max;

    char *p = (char *) (pa0 + (srcva - va0));
    while(n > 0){
      if(*p == '\0'){
        *dst = '\0';
        got_null = 1;
        break;
      } else {
        *dst = *p;
      }
      --n;
      --max;
      p++;
      dst++;
    }

    srcva = va0 + PGSIZE;
  }
  if(got_null){
    return 0;
  } else {
    return -1;
  }
}

// allocate and map user memory if process is referencing a page
// that was lazily allocated in sys_sbrk().
// returns 0 if va is invalid or already mapped, or if
// out of physical memory, and physical address if successful.
uint64
vmfault(pagetable_t pagetable, uint64 va, int read)
{
  uint64 mem;
  uint64 pa;
  pte_t *pte;
  int level = 0;
  struct proc *p = myproc();
  struct linux_mm *mm = p->mm;

  struct vma *v = 0;
  uint64 a = PGROUNDDOWN(va);

  if(va >= MAXVA || a >= MAXVA)
    return 0;
  va = PGROUNDDOWN(va);
  pte = walk_with_level(pagetable, va, 0, &level);
  if(pte && (*pte & PTE_V)){
    if(((*pte & PTE_COW) != 0) && !read){
      pa = PTE2PA(*pte);
      if(level == 1 && PTE_LEAF(*pte)){
        uint64 off = va & (SUPERPGSIZE - 1);
        uint flags = (PTE_FLAGS(*pte) | PTE_W) & ~PTE_COW;
        if(superref_get(pa) == 1){
          *pte = PA2PTE(pa) | flags;
          sfence_vma();
          return pa + off;
        }
        mem = (uint64)superalloc();
