  if(lenaddr != 0){
    uint len32;
    if(copyin(myproc()->pagetable, (char *)&len32, lenaddr, sizeof(len32)) < 0)
      return -1;
    if(len32 < len)
      len = len32;
    len32 = sizeof(*sa);
    if(copyout(myproc()->pagetable, lenaddr, (char *)&len32, sizeof(len32)) < 0)
      return -1;
  }
  if(addr != 0 && copyout(myproc()->pagetable, addr, (char *)sa, len) < 0)
    return -1;
  return 0;
}

