    np->pagetable = p->pagetable;
    uvmunmap(np->pagetable, np->trapframe_va, 1, 0);
    if(mappages(np->pagetable, np->trapframe_va, PGSIZE,
                (uint64)(np->trapframe), PTE_R | PTE_W) < 0){
