  acquire(&wait_lock);
  linux_group_set_exiting(p->linux_group, status);
  for(struct proc *q = proc; q < &proc[NPROC]; q++){
    if(q == p || q->state == UNUSED)
      continue;
    if(!linux_same_thread_group(p, q))
      continue;
    acquire(&q->lock);
    q->killed = 1;
    if(q->state == SLEEPING)
      q->state = RUNNABLE;
    release(&q->lock);
  }
  release(&wait_lock);

  kexit(status);
