// Physical memory allocator, for user processes,
// kernel stacks, page-table pages,
// and pipe buffers. Allocates whole 4096-byte pages.

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "riscv.h"
#include "defs.h"

void freerange(void *pa_start, void *pa_end);

extern char end[]; // first address after kernel.
                   // defined by kernel.ld.

struct run {
  struct run *next;
};

struct {
  struct spinlock lock;
  struct run *freelist;
} kmem[NCPU];

static struct spinlock ref_lock;

struct superrun {
  struct superrun *next;
};

struct {
  struct spinlock lock;
  struct superrun *freelist;
} supermem;

static uint64 super_start;
static uint64 super_end;
static uint refcnt[(PHYSTOP - SUPERPGNUM * SUPERPGSIZE) / PGSIZE];
static uint super_refcnt[SUPERPGNUM];

static inline uint
pa2ref(uint64 pa)
{
  return pa / PGSIZE;
}

static inline uint
pa2super(uint64 pa)
{
  return (pa - super_start) / SUPERPGSIZE;
}

void
kinit()
{
  initlock(&ref_lock, "refcnt");
  initlock(&supermem.lock, "supermem");
  super_start = PHYSTOP - SUPERPGNUM * SUPERPGSIZE;
  super_start = SUPERPGROUNDDOWN(super_start);
  super_end = super_start + SUPERPGNUM * SUPERPGSIZE;

  for(int i = 0; i < SUPERPGNUM; i++){
    char *p = (char*)(super_start + (uint64)i * SUPERPGSIZE);
    acquire(&supermem.lock);
    super_refcnt[pa2super((uint64)p)] = 1;
    release(&supermem.lock);
    superfree(p);
  }

  for(int i = 0; i < NCPU; i++){
    uint64 base = PGROUNDUP((uint64)end);
    uint64 total_mem = super_start - base;
    uint64 piece = total_mem / NCPU;
    uint64 s = base + i * piece;
    uint64 e = (i == NCPU - 1)? super_start : base + (i + 1) * piece;
    initlock(&kmem[i].lock, "kmem");
    freerange((void*)s, (void*)e);
  }
}

void
freerange(void *pa_start, void *pa_end)
{
  char *p;
  p = (char*)PGROUNDUP((uint64)pa_start);
  for(; p + PGSIZE <= (char*)pa_end; p += PGSIZE){
    acquire(&ref_lock);
    refcnt[pa2ref((uint64)p)] = 1;
    release(&ref_lock);
    kfree(p);
  }
}

// Free the page of physical memory pointed at by pa,
// which normally should have been returned by a
// call to kalloc().  (The exception is when
// initializing the allocator; see kinit above.)
void
kfree(void *pa)
{
  struct run *r;
  int freeit = 0;

  push_off();
  int cpu_id = cpuid();
  pop_off();
  if(((uint64)pa % PGSIZE) != 0 || (char*)pa < end || (uint64)pa >= super_start)
    panic("kfree");

  acquire(&ref_lock);
  if(refcnt[pa2ref((uint64)pa)] < 1)
    panic("kfree ref");
  refcnt[pa2ref((uint64)pa)]--;
  if(refcnt[pa2ref((uint64)pa)] == 0)
    freeit = 1;
  release(&ref_lock);

  if(!freeit)
    return;

  // Fill with junk to catch dangling refs.
  memset(pa, 1, PGSIZE);

  r = (struct run*)pa;

  acquire(&kmem[cpu_id].lock);
  r->next = kmem[cpu_id].freelist;
  kmem[cpu_id].freelist = r;
  release(&kmem[cpu_id].lock);
}

void
superfree(void *pa)
{
  struct superrun *r;
  int freeit = 0;

  if(((uint64)pa % SUPERPGSIZE) != 0 || (uint64)pa < super_start ||
     (uint64)pa + SUPERPGSIZE > super_end)
    panic("superfree");

  acquire(&supermem.lock);
  if(super_refcnt[pa2super((uint64)pa)] < 1)
    panic("superfree ref");
  super_refcnt[pa2super((uint64)pa)]--;
  if(super_refcnt[pa2super((uint64)pa)] == 0)
    freeit = 1;
  release(&supermem.lock);

  if(!freeit)
    return;

  memset(pa, 1, SUPERPGSIZE);

  r = (struct superrun*)pa;

  acquire(&supermem.lock);
  r->next = supermem.freelist;
  supermem.freelist = r;
  release(&supermem.lock);
}

void *
superalloc(void)
{
  struct superrun *r;

  acquire(&supermem.lock);
  r = supermem.freelist;
  if(r)
    supermem.freelist = r->next;
  if(r)
    super_refcnt[pa2super((uint64)r)] = 1;
  release(&supermem.lock);

  if(r)
    memset((char*)r, 5, SUPERPGSIZE);
  return (void*)r;
}

// Allocate one 4096-byte page of physical memory.
// Returns a pointer that the kernel can use.
// Returns 0 if the memory cannot be allocated.
void *
kalloc(void)
{
  struct run *r;

  push_off();
  int cpu_id = cpuid();
  pop_off();

  acquire(&kmem[cpu_id].lock);
  r = kmem[cpu_id].freelist;
  if(r)
  kmem[cpu_id].freelist = r->next;
  if(r){ 
    acquire(&ref_lock);
    refcnt[pa2ref((uint64)r)] = 1;
    release(&ref_lock); 
  }
  release(&kmem[cpu_id].lock);
  if(r){
    memset((char*)r, 5, PGSIZE); // fill with junk
    return (void*)r;
  }

  if(!r){
    for(int i = 0; i < NCPU; i++){
      if(cpu_id == i) continue;
      int flag = 0;
      for(int j = 0; j < 8; j++){
        struct run* p = 0;

        acquire(&kmem[i].lock);
        p = kmem[i].freelist;
        if(p)
          kmem[i].freelist = p->next;
        release(&kmem[i].lock);
        if(!p) break;

        acquire(&kmem[cpu_id].lock);
        p->next = kmem[cpu_id].freelist;
        kmem[cpu_id].freelist = p;
        release(&kmem[cpu_id].lock);
        flag++;
      }
      if(flag) break;
    }
  }
  acquire(&kmem[cpu_id].lock);
  r = kmem[cpu_id].freelist;
  if(r)
    kmem[cpu_id].freelist = r->next;
  if(r){ 
    acquire(&ref_lock); 
    refcnt[pa2ref((uint64)r)] = 1; 
    release(&ref_lock); 
  }
  release(&kmem[cpu_id].lock);
  if(r)
    memset((char*)r, 5, PGSIZE); // fill with junk
  return (void*)r;
}

void
kref_inc(uint64 pa)
{
  if((pa % PGSIZE) != 0 || pa >= super_start)
    panic("kref_inc");
  acquire(&ref_lock);
  refcnt[pa2ref(pa)]++;
  release(&ref_lock);
}

uint
kref_get(uint64 pa)
{
  uint n;
  if((pa % PGSIZE) != 0 || pa >= super_start)
    panic("kref_get");

  acquire(&ref_lock);
  n = refcnt[pa2ref(pa)];
  release(&ref_lock);
  return n;
}

void
superref_inc(uint64 pa)
{
  if((pa % SUPERPGSIZE) != 0 || pa < super_start || pa + SUPERPGSIZE > super_end)
    panic("superref_inc");

  acquire(&supermem.lock);
  super_refcnt[pa2super(pa)]++;
  release(&supermem.lock);
}

uint
superref_get(uint64 pa)
{
  uint n;
  if((pa % SUPERPGSIZE) != 0 || pa < super_start || pa + SUPERPGSIZE > super_end)
    panic("superref_get");

  acquire(&supermem.lock);
  n = super_refcnt[pa2super(pa)];
  release(&supermem.lock);
  return n;
}

static int
linux_futex_cmp(int old, int cmp, int cmparg)
{
  switch(cmp){
  case 0: return old == cmparg; // FUTEX_OP_CMP_EQ
  case 1: return old != cmparg; // FUTEX_OP_CMP_NE
  case 2: return old < cmparg;  // FUTEX_OP_CMP_LT
  case 3: return old <= cmparg; // FUTEX_OP_CMP_LE
  case 4: return old > cmparg;  // FUTEX_OP_CMP_GT
  case 5: return old >= cmparg; // FUTEX_OP_CMP_GE
  default: return 0;
  }
}

static int
linux_futex_wake_op(uint64 uaddr, uint64 uaddr2, int nrwake, int nrwake2,
                    int encoded)
{
  int old, new;
  int op = (encoded >> 28) & 0xf;
  int cmp = (encoded >> 24) & 0xf;
  int oparg = linux_futex_op_arg(op, (encoded >> 12) & 0xfff);
  int cmparg = encoded & 0xfff;

  if(copyin(myproc()->pagetable, (char *)&old, uaddr2, sizeof(old)) < 0)
    return -14; // EFAULT

  // Apply the encoded arithmetic/bit operation to uaddr2.
  switch(op & 7){
  case 0: new = oparg; break;        // FUTEX_OP_SET
  case 1: new = old + oparg; break;  // FUTEX_OP_ADD
  case 2: new = old | oparg; break;  // FUTEX_OP_OR
  case 3: new = old & ~oparg; break; // FUTEX_OP_ANDN
  case 4: new = old ^ oparg; break;  // FUTEX_OP_XOR
  default: return -38; // ENOSYS
  }

  if(copyout(myproc()->pagetable, uaddr2, (char *)&new, sizeof(new)) < 0)
    return -14; // EFAULT

  // Wake uaddr waiters unconditionally; wake uaddr2 waiters only if cmp passes.
  int count = linux_futex_wake_n_locked(uaddr, nrwake, 0xffffffffU);
  if(linux_futex_cmp(old, cmp, cmparg))
    count += linux_futex_wake_n_locked(uaddr2, nrwake2, 0xffffffffU);
  return count;
}

