uint64
sys_sbrk(void)
{
  // xv6 heap growth; supports eager allocation and lab lazy allocation.
  uint64 addr;
  int t;
  int n;

  argint(0, &n);
  argint(1, &t);
  addr = myproc()->mm->sz;

  if(t == SBRK_EAGER || n < 0) {
    if(growproc(n) < 0) {
      return -1;
    }
  } else {
    // Lazily allocate memory for this process: increase its memory
    // size but don't allocate memory. If the processes uses the
    // memory, vmfault() will allocate it.
    if(addr + n < addr)
      return -1;
    acquire(&myproc()->mm->lock);
    myproc()->mm->sz += n;
    release(&myproc()->mm->lock);
  }
  return addr;
}

uint64
sys_linux_brk(void)
{
  // Linux brk sets the process break and returns the current break on failure.
  uint64 addr;
  uint64 ret;
  struct proc *p = myproc();
  struct linux_mm *mm = p->mm;

  argaddr(0, &addr);
  acquire(&mm->lock);
  if(mm->linux_brk == 0)
    mm->linux_brk = mm->sz;
  if(addr == 0){
    uint64 brk = mm->linux_brk;
    release(&mm->lock);
    return brk;
  }
  if(addr < mm->linux_brk){
    uint64 brk = mm->linux_brk;
    release(&mm->lock);
    return brk;
  }
  if(mm->linux_brk_limit && addr >= mm->linux_brk_limit){
    uint64 brk = mm->linux_brk;
    release(&mm->lock);
    return brk;
  }
  if(PGROUNDUP(addr) > mm->sz){
    uint64 sz = uvmalloc(p->pagetable, mm->sz, PGROUNDUP(addr), PTE_W);
    if(sz == 0){
      uint64 brk = mm->linux_brk;
      release(&mm->lock);
      return brk;
    }
    mm->sz = sz;
  }
  mm->linux_brk = addr;
  ret = mm->linux_brk;
  release(&mm->lock);
  return ret;
}

