uint64
sys_pause(void)
{
  // xv6 sleep for n clock ticks.
  int n;
  uint ticks0;
  argint(0, &n);
  //backtrace();
  if(n < 0)
    n = 0;
  acquire(&tickslock.l);
  ticks0 = ticks;
  while(ticks - ticks0 < n){
    if(killed(myproc())){
      release(&tickslock.l);
