static int
lwext4_map_open_flags(int xv6_flags)
{
  int flags;

  switch(xv6_flags & 3){
  case XV6_O_WRONLY:
    flags = O_WRONLY;
    break;
  case XV6_O_RDWR:
    flags = O_RDWR;
    break;
  default:
    flags = O_RDONLY;
    break;
  }
  if(xv6_flags & XV6_O_CREATE)
    flags |= O_CREAT;
  if(xv6_flags & XV6_O_TRUNC)
    flags |= O_TRUNC;
  return flags;
}

static int
lwext4_clean_path(char *dst, int dstsz, const char *path)
{
  int di = 1;
  int si = 0;

  if(dst == 0 || dstsz < 2 || path == 0)
    return -1;

  if(strncmp(path, LWEXT4_VFS_PREFIX, strlen(LWEXT4_VFS_PREFIX)) == 0 &&
     (path[strlen(LWEXT4_VFS_PREFIX)] == 0 ||
      path[strlen(LWEXT4_VFS_PREFIX)] == '/')){
    path += strlen(LWEXT4_VFS_PREFIX);
    if(path[0] == 0)
      path = "/";
  }

  dst[0] = '/';
  dst[1] = 0;
  while(path[si]){
    char elem[MAXPATH];
    int n = 0;

    while(path[si] == '/')
      si++;
    if(path[si] == 0)
      break;

    while(path[si] && path[si] != '/' && n < sizeof(elem) - 1)
      elem[n++] = path[si++];
    elem[n] = 0;
    while(path[si] && path[si] != '/')
      si++;

    if(n == 0 || (n == 1 && elem[0] == '.'))
      continue;
    if(n == 2 && elem[0] == '.' && elem[1] == '.'){
      if(di > 1){
        di--;
        while(di > 1 && dst[di - 1] != '/')
          di--;
      }
      dst[di] = 0;
      continue;
    }

    if(di > 1){
      if(di >= dstsz - 1)
        return -1;
      dst[di++] = '/';
    }
    for(int i = 0; i < n; i++){
      if(di >= dstsz - 1)
        return -1;
      dst[di++] = elem[i];
    }
    dst[di] = 0;
  }

  if(di == 0)
    dst[di++] = '/';
  dst[di] = 0;
  return 0;
}

