vfs_resolve(char *path, struct vfs_path *out)
{
  int best = -1;
  int bestlen = -1;
  int target_len;
  char clean[MAXPATH];
  char *inner;

  if(path == 0 || out == 0 || path[0] != '/')
    return -1;
  vfs_clean_path(clean, sizeof(clean), path);
  path = clean;

