  // a set (not a ring) of DMA descriptors, with which the
  // driver tells the device where to read and write individual
  // disk operations. there are NUM descriptors.
  // most commands consist of a "chain" (a linked list) of a couple of
  // these descriptors.
  struct virtq_desc *desc;

  // a ring in which the driver writes descriptor numbers
  // that the driver would like the device to process.  it only
  // includes the head descriptor of each chain. the ring has
  // NUM elements.
  struct virtq_avail *avail;

  // a ring in which the device writes descriptor numbers that
  // the device has finished processing (just the head of each chain).
  // there are NUM used ring entries.
  struct virtq_used *used;

  // our own book-keeping.
  char free[NUM];  // is a descriptor free?
  uint16 used_idx; // we've looked this far in used[2..NUM].

  {SYS_unbind, sys_unbind},
  {SYS_send, sys_send},
  {SYS_recv, sys_recv},
  {SYS_cpupin, sys_cpupin},
  {SYS_halt, sys_halt},
};

static uint64 (*syscall_lookup(int num))(void)
{
  // Prefer Linux ABI numbers, then fall back to xv6 private extensions.
  for(int i = 0; i < NELEM(linux_syscalls); i++){
    if(linux_syscalls[i].num == num)
      return linux_syscalls[i].fn;
  }
  for(int i = 0; i < NELEM(xv6_syscalls); i++){
    if(xv6_syscalls[i].num == num)
      return xv6_syscalls[i].fn;
  }
  return 0;
}

void
syscall(void)
{
  // Dispatch the syscall number held in a7 and place the result in a0.
  int num;
  struct proc *p = myproc();
  uint64 (*fn)(void);

  num = p->trapframe->a7;
  if((fn = syscall_lookup(num)) != 0) {
    p->trapframe->a0 = fn();
  } else {
    printf("%d %s: unknown linux sys call %d\n",
            p->pid, p->name, num);
    p->trapframe->a0 = -1;
  }
}

